%[text] # 例3.5（境界処理）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example03_05"; % mfilename

imgname = "msipimg03";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## フィルタ処理前の画像表示
figure(1) %[output:64078bdf]
imshow(X)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]
%%
%[text] ## フィルタの設定
f = fspecial('average',2);

%%
%[text] ## 零値拡張
Yz = imfilter(X,f,'corr','same');
figure(2) %[output:3785ec24]
imshow(Yz) %[output:3785ec24]
title('零値拡張')  %[output:3785ec24]

%%
%[text] ## 周期拡張
Yp = imfilter(X,f,'corr','circular');
figure(3) %[output:949f124a]
imshow(Yp) %[output:949f124a]
title('周期拡張')  %[output:949f124a]

%%
%[text] ## 複製拡張
Yr = imfilter(X,f,'corr','replicate');
figure(4) %[output:55d3674c]
imshow(Yr) %[output:55d3674c]
title('複製拡張')  %[output:55d3674c]

%%
%[text] ## 対称拡張
Ys = imfilter(X,f,'corr','symmetric');
figure(5) %[output:0b548ad7]
imshow(Ys) %[output:0b548ad7]
title('対称拡張')  %[output:0b548ad7]

%%
%[text] ## 結果出力

imwrite(Yz(end*(13/16):end,end*(13/16):end),fullfile(resfolder,"fig03-04a.png"))
imwrite(Yp(end*(13/16):end,end*(13/16):end),fullfile(resfolder,"fig03-04b.png"))
imwrite(Yr(end*(13/16):end,end*(13/16):end),fullfile(resfolder,"fig03-04c.png"))
imwrite(Ys(end*(13/16):end,end*(13/16):end),fullfile(resfolder,"fig03-04d.png"))

